// ============================================================
// WF-04: CHECK-IN WEB
// Webhook GET que sirve HTML mobile-first
// ============================================================

const helpers = this.helpers;
const SUPABASE_URL = $env.SUPABASE_URL;
const SUPABASE_KEY = $env.SUPABASE_SERVICE_KEY;
const WA_TOKEN = $env.META_WHATSAPP_TOKEN;
const PHONE_ID = '963190063548521';
const TELEGRAM_TOKEN = $env.TELEGRAM_BOT_TOKEN || '';
const TELEGRAM_CHAT = $env.TELEGRAM_CHAT_ID || '';

function argDate(d) { return new Date(d.getTime() - 3*60*60*1000); }
const DIAS = ['Dom','Lun','Mar','Mi\u00e9','Jue','Vie','S\u00e1b'];
const MESES = ['Ene','Feb','Mar','Abr','May','Jun','Jul','Ago','Sep','Oct','Nov','Dic'];
function fmtLarga(d) { return `${DIAS[d.getUTCDay()]} ${d.getUTCDate()} de ${MESES[d.getUTCMonth()]}`; }
function fmtHora(d) { return `${String(d.getUTCHours()).padStart(2,'0')}:${String(d.getUTCMinutes()).padStart(2,'0')}`; }

async function supaGet(table, params) {
  try { return await helpers.httpRequest({ method: 'GET', url: `${SUPABASE_URL}/rest/v1/${table}`, qs: params, headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}` } }); }
  catch (e) { return []; }
}
async function supaUpdate(table, filters, data) {
  try { await helpers.httpRequest({ method: 'PATCH', url: `${SUPABASE_URL}/rest/v1/${table}`, qs: filters, headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}`, 'Content-Type': 'application/json' }, body: JSON.stringify({ ...data, updated_at: new Date().toISOString() }) }); }
  catch (e) {}
}

const token = $input.first().json?.query?.token || '';
const action = $input.first().json?.query?.action || '';

// CSS compartido
const CSS = `
  * { margin:0; padding:0; box-sizing:border-box; }
  body { font-family: system-ui,-apple-system,sans-serif; background:#F8FAFC; color:#1E293B; min-height:100vh; display:flex; justify-content:center; align-items:center; padding:16px; }
  .card { background:#fff; border-radius:16px; box-shadow:0 4px 24px rgba(0,0,0,0.08); padding:32px 24px; max-width:400px; width:100%; text-align:center; }
  .logo { font-size:24px; font-weight:700; color:#2563EB; margin-bottom:4px; }
  .subtitle { color:#64748B; font-size:14px; margin-bottom:24px; }
  .divider { height:1px; background:#E2E8F0; margin:20px 0; }
  .greeting { font-size:20px; font-weight:600; margin-bottom:16px; }
  .info-box { background:#F1F5F9; border-radius:12px; padding:16px; text-align:left; margin-bottom:20px; }
  .info-row { display:flex; align-items:center; gap:8px; margin-bottom:8px; font-size:15px; }
  .info-row:last-child { margin-bottom:0; }
  .btn { display:block; width:100%; padding:16px; border:none; border-radius:12px; font-size:17px; font-weight:600; cursor:pointer; transition:all 0.2s; }
  .btn-primary { background:#2563EB; color:#fff; }
  .btn-primary:hover { background:#1D4ED8; }
  .btn-primary:disabled { background:#94A3B8; cursor:not-allowed; }
  .btn-success { background:#10B981; color:#fff; }
  .success-icon { font-size:48px; margin-bottom:12px; }
  .step-box { background:#EFF6FF; border:1px solid #BFDBFE; border-radius:12px; padding:16px; text-align:left; margin:16px 0; font-size:14px; line-height:1.6; }
  .stats { display:flex; justify-content:space-around; margin-top:16px; }
  .stat { text-align:center; }
  .stat-value { font-size:20px; font-weight:700; color:#2563EB; }
  .stat-label { font-size:12px; color:#64748B; }
  .error-icon { font-size:48px; margin-bottom:12px; }
  .error-text { color:#EF4444; font-weight:600; margin-bottom:8px; }
`;

function htmlPage(title, body) {
  return `<!DOCTYPE html><html lang="es"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>${title}</title><style>${CSS}</style></head><body>${body}</body></html>`;
}

// Sin token
if (!token) {
  return [{ json: { html: htmlPage('Error', '<div class="card"><div class="error-icon">\u274c</div><div class="error-text">Link inv\u00e1lido</div><p>Este link no es v\u00e1lido. Ped\u00ed un nuevo link de check-in por WhatsApp.</p></div>') } }];
}

// Buscar turno
const turnos = await supaGet('consultorio_turnos', { check_in_token: `eq.${token}`, select: 'id,fecha_hora,estado,tipo_pago,check_in_at,paciente_id,profesional_id' });
const turno = turnos?.[0];

if (!turno) {
  return [{ json: { html: htmlPage('No encontrado', '<div class="card"><div class="error-icon">\u274c</div><div class="error-text">Link inv\u00e1lido</div><p>No encontramos un turno asociado a este link.</p></div>') } }];
}

// Turno cancelado
if (['cancelado','auto_cancelado'].includes(turno.estado)) {
  return [{ json: { html: htmlPage('Cancelado', '<div class="card"><div class="error-icon">\u274c</div><div class="error-text">Turno cancelado</div><p>Este turno fue cancelado. Pod\u00e9s agendar uno nuevo por WhatsApp.</p></div>') } }];
}

// Turno ya paso
const turnoDate = new Date(turno.fecha_hora);
if (turnoDate.getTime() < Date.now() - 2*60*60*1000) {
  return [{ json: { html: htmlPage('Vencido', '<div class="card"><div class="error-icon">\u23f0</div><div class="error-text">Link vencido</div><p>El turno asociado ya pas\u00f3. Pod\u00e9s agendar uno nuevo por WhatsApp.</p></div>') } }];
}

const pac = await supaGet('consultorio_pacientes', { id: `eq.${turno.paciente_id}`, select: 'nombre,dni,obra_social' });
const prof = await supaGet('consultorio_profesionales', { id: `eq.${turno.profesional_id}`, select: 'nombre,especialidad,consultorio' });
const nombre = pac?.[0]?.nombre || 'Paciente';
const primerNombre = nombre.split(' ')[0];
const d = argDate(turnoDate);

// === PROCESAR CHECK-IN ===
if (action === 'checkin' && !turno.check_in_at) {
  await supaUpdate('consultorio_turnos', { id: `eq.${turno.id}` }, { estado: 'presente', check_in_at: new Date().toISOString() });

  // Contar pacientes antes
  const antes = await supaGet('consultorio_turnos', { profesional_id: `eq.${turno.profesional_id}`, estado: 'eq.presente', select: 'check_in_at', order: 'check_in_at.asc' });
  const orden = (antes?.length || 1);
  const pacAntes = Math.max(0, orden - 1);
  const tiempoEst = pacAntes * (prof?.[0]?.duracion_turno_min || 15);
  const numOrden = String(orden).padStart(4, '0');

  // Notificar a recepcion por Telegram
  if (TELEGRAM_TOKEN && TELEGRAM_CHAT) {
    const tipoMsg = turno.tipo_pago === 'obra_social' ? `OS: ${pac[0]?.obra_social || '?'} \u2014 Verificar credencial + DNI + coseguro` : `Particular \u2014 Cobrar consulta $45.000`;
    const tgMsg = `\ud83d\udd14 NUEVO CHECK-IN\n\nPaciente: ${nombre}\nDNI: ${pac[0]?.dni || '?'}\nTurno: ${fmtHora(d)} hs \u2014 ${prof[0]?.nombre || '?'} (${prof[0]?.especialidad || '?'})\nTipo: ${tipoMsg}\nLlegada: ${fmtHora(argDate(new Date()))} hs\nOrden: #${numOrden}`;
    try {
      await helpers.httpRequest({ method: 'POST', url: `https://api.telegram.org/bot${TELEGRAM_TOKEN}/sendMessage`, headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ chat_id: TELEGRAM_CHAT, text: tgMsg }) });
    } catch (e) {}
  }

  const instruccion = turno.tipo_pago === 'obra_social'
    ? `Acercate a recepci\u00f3n con tu credencial de ${pac[0]?.obra_social || 'obra social'} y DNI para el coseguro.`
    : 'Acercate a recepci\u00f3n para abonar la consulta ($45.000).';

  const successHtml = `
    <div class="card">
      <div class="success-icon">\u2705</div>
      <div class="greeting">CHECK-IN COMPLETADO</div>
      <p style="color:#64748B;margin-bottom:16px">${primerNombre}, recepci\u00f3n ya sabe que llegaste.</p>
      <div class="step-box">
        \ud83d\udccb <strong>Pr\u00f3ximo paso:</strong><br>
        ${instruccion}<br><br>
        Despu\u00e9s pas\u00e1 a sala de espera, Piso 1.
      </div>
      <div class="stats">
        <div class="stat"><div class="stat-value">#${numOrden}</div><div class="stat-label">Tu orden</div></div>
        <div class="stat"><div class="stat-value">${pacAntes}</div><div class="stat-label">Antes que vos</div></div>
        <div class="stat"><div class="stat-value">~${tiempoEst}m</div><div class="stat-label">Estimado</div></div>
      </div>
    </div>`;

  return [{ json: { html: htmlPage('Check-in OK', successHtml) } }];
}

// === YA HIZO CHECK-IN ===
if (turno.check_in_at) {
  const antes = await supaGet('consultorio_turnos', { profesional_id: `eq.${turno.profesional_id}`, estado: 'eq.presente', select: 'check_in_at', order: 'check_in_at.asc' });
  let miPos = 0; for (let i=0;i<(antes?.length||0);i++) { if (new Date(antes[i].check_in_at) <= new Date(turno.check_in_at)) miPos = i+1; }
  const pacAntes = Math.max(0, miPos - 1);
  const tiempoEst = pacAntes * (prof?.[0]?.duracion_turno_min || 15);

  return [{ json: { html: htmlPage('Ya check-in', `
    <div class="card">
      <div class="success-icon">\u2705</div>
      <div class="greeting">Ya hiciste check-in</div>
      <div class="info-box">
        <div class="info-row">\ud83d\udcc5 ${fmtHora(d)} hs \u2014 ${prof[0]?.nombre || '?'}</div>
        <div class="info-row">\ud83c\udfe0 ${prof[0]?.consultorio || ''}, Piso 1</div>
      </div>
      <div class="stats">
        <div class="stat"><div class="stat-value">${pacAntes}</div><div class="stat-label">Antes que vos</div></div>
        <div class="stat"><div class="stat-value">~${tiempoEst}m</div><div class="stat-label">Estimado</div></div>
