const N8N_URL = $input.first().json?.headers?.host ? `https://${$input.first().json.headers.host}` : N8N_BASE_URL;
const checkinAction = `${N8N_URL}/webhook/consultorio-checkin?token=${token}&action=checkin`;

const mainHtml = `
  <div class="card">
    <div class="logo">\ud83c\udfe5 POLICONSULTORIO RIVADAVIA</div>
    <div class="subtitle">Check-in digital</div>
    <div class="divider"></div>
    <div class="greeting">Hola ${primerNombre}!</div>
    <p style="color:#64748B;margin-bottom:20px">Tu turno de hoy:</p>
    <div class="info-box">
      <div class="info-row">\ud83d\udcc5 ${fmtLarga(d)}, ${fmtHora(d)} hs</div>
      <div class="info-row">\ud83d\udc68\u200d\u2695\ufe0f ${prof[0]?.nombre || '?'} \u2014 ${prof[0]?.especialidad || '?'}</div>
      <div class="info-row">\ud83c\udfe0 ${prof[0]?.consultorio || ''}, Piso 1</div>
    </div>
    <button class="btn btn-primary" id="checkinBtn" onclick="doCheckin()">\u2705 YA LLEGU\u00c9</button>
    <p style="color:#94A3B8;font-size:12px;margin-top:16px">Av. Rivadavia 4520, Caballito, CABA</p>
  </div>
  <script>
    async function doCheckin() {
      const btn = document.getElementById('checkinBtn');
      btn.disabled = true; btn.textContent = 'Procesando...';
      try {
        const r = await fetch('${checkinAction}');
        const html = await r.text();
        document.body.innerHTML = html.match(/<body>(.*)<\\/body>/s)?.[1] || html;
      } catch(e) {
        btn.textContent = 'Error, intent\u00e1 de nuevo';
        btn.disabled = false;
      }
    }
  </script>`;

return [{ json: { html: htmlPage('Check-in', mainHtml) } }];

